function displayPartnerCell(row,key,type){
 if(key==='util')return typeof row[key]==='number'?<UtilBar value={row[key]}/>:row[key];
 if(key==='reliability')return relBadge(row[key]);
 if(key==='status')return statusBadge(row[key]);
 // 'cod' is currency for entrepreneurs & distributors, but % for brands
 if(key==='cod')return type==='brands'?`${row[key]}%`:`₹${fmt(row[key])}`;
 if(key==='value')return `₹${fmt(row[key])}`;
 // 'weight' is kg for brands, load-factor % for fleet
 if(key==='weight')return type==='brands'?`${row[key]} kg`:`${row[key]}%`;
 if(['volume','onTime','compliance'].includes(key))return `${row[key]}%`;
 return fmt(row[key]);
}
